mapper.select:
select YYYYMM, SEL_CODE, SITE AS SITE_ORG, CASE WHEN SITE='HQ' then '본사' WHEN site='VN' then 'VINA' end as SITE, MAT_CODE, MAT_DESC, [SIZE], IN_QTY, UNIT_COST, IN_AMT, COST_GUBUN, MAT_CLASS, MODEL, MODEL_N_TYPE from DOI_MATERIAL_RESC where 1=1
and yyyymm = #{yyyymm}
and site = #{site}
order BY MAT_CODE;

DROP TABLE IF EXISTS #TempTable1;

CREATE TABLE #TempTable1 (
	YYYYMM varchar(6) COLLATE Korean_Wansung_CI_AS NULL,
	SEL_CODE varchar(6) COLLATE Korean_Wansung_CI_AS NULL,
	SITE varchar(4) COLLATE Korean_Wansung_CI_AS NULL,
	MAT_CODE varchar(24) COLLATE Korean_Wansung_CI_AS NULL,
	MAT_DESC nvarchar(50) COLLATE Korean_Wansung_CI_AS NULL,
	[SIZE] varchar(40) COLLATE Korean_Wansung_CI_AS NULL,
	IN_QTY real NULL,
	UNIT_COST real NULL,
	IN_AMT real NULL,
	COST_GUBUN nvarchar(15) COLLATE Korean_Wansung_CI_AS NULL,
	MAT_CLASS nvarchar(10) COLLATE Korean_Wansung_CI_AS NULL,
	MODEL varchar(10) COLLATE Korean_Wansung_CI_AS NULL,
	MODEL_N_TYPE varchar(15) COLLATE Korean_Wansung_CI_AS NULL
);

